def _split_code_and_comment(line: str) -> tuple[str, str | None]:
    """Split a line into (code, comment) at the first unquoted `#`."""
    in_string = False
    string_char = ""
    escape = False
    for i, ch in enumerate(line):
        if escape:
            escape = False
            continue
        if ch == "\\":
            escape = True
            continue
        if in_string:
            if ch == string_char:
                in_string = False
            continue
        if ch in ("'", '"'):
            in_string = True
            string_char = ch
            continue
        if ch == "#":
            return line[:i], line[i + 1 :].strip()
    return line, None


def _parse_calls_and_comments(text: str) -> tuple[list[dict[str, Any]], list[str | None]]:
    """Parse raw text containing JSON tool call objects interleaved with Python comments.

    Comments that precede, are inline with, or immediately follow a JSON object are all
    associated with that object. Returns the parsed dicts alongside the combined comment
    string for each (or None if no comment was found).
    """
    blocks = []
    floating_comments: list[str] = []
    current: dict[str, Any] | None = None

    for raw_line in text.split("\n"):
        code_part, comment_part = _split_code_and_comment(raw_line)
        if comment_part:
            if current is not None:
                current["comments"].append(comment_part)
            else:
                floating_comments.append(comment_part)

        stripped_code = code_part.strip()
        if not stripped_code:
            continue

        for ch in stripped_code:
            if ch == "{":
                if current is not None and current["depth"] == 0 and current["json_lines"]:
                    blocks.append(current)
                    current = None
                if current is None:
                    current = {"json_lines": [], "comments": floating_comments, "depth": 0}
                    floating_comments = []
                current["depth"] += 1
            elif ch == "}":
                if current is not None:
                    current["depth"] -= 1

        if current is not None:
            current["json_lines"].append(code_part)

    if current is not None:
        blocks.append(current)

    parsed_dicts = []
    comments_list = []
    for block in blocks:
        parsed_dicts.append(json.loads("\n".join(block["json_lines"])))
        comments_list.append("\n".join(block["comments"]) if block["comments"] else None)

    return parsed_dicts, comments_list


