_METADATA_FIELDS = ("note", "comment", "annotation", "tags", "priority", "meta")


def _canonicalize_value(value: Any) -> Any:
    """Recursively canonicalize a value for stable fingerprinting.

    Dict keys are sorted, tuples are converted to lists, and strings are stripped of
    leading/trailing whitespace. Numeric and boolean types are left untouched.
    """
    if isinstance(value, dict):
        return {k: _canonicalize_value(v) for k, v in sorted(value.items())}
    if isinstance(value, (list, tuple)):
        return [_canonicalize_value(v) for v in value]
    if isinstance(value, str):
        return value.strip()
    return value


def _compute_fingerprint(name: str, args: dict[str, Any]) -> tuple[str, str]:
    """Compute a stable (fingerprint, id) pair for a tool call's name and args."""
    canonical = {"name": name, "args": _canonicalize_value(args)}
    serialized = json.dumps(canonical, sort_keys=True, separators=(",", ":"))
    fingerprint = hashlib.sha256(serialized.encode("utf-8")).hexdigest()
    return fingerprint, fingerprint[:8]


def _split_code_and_comment(line: str) -> tuple[str, str | None]:
    """Split a line into (code, comment) at the first unquoted `#`."""
    in_string = False
    string_char = ""
    escape = False
    for i, ch in enumerate(line):
        if escape:
            escape = False
            continue
        if ch == "\\":
            escape = True
            continue
        if in_string:
            if ch == string_char:
                in_string = False
            continue
        if ch in ("'", '"'):
            in_string = True
            string_char = ch
            continue
        if ch == "#":
            return line[:i], line[i + 1 :].strip()
    return line, None


def _parse_calls_and_comments(text: str) -> tuple[list[dict[str, Any]], list[str | None]]:
    """Parse raw text containing JSON tool call objects interleaved with Python comments.

    Comments that precede, are inline with, or immediately follow a JSON object are all
    associated with that object. Returns the parsed dicts alongside the combined comment
    string for each (or None if no comment was found).
    """
    blocks = []
    floating_comments: list[str] = []
    current: dict[str, Any] | None = None

    for raw_line in text.split("\n"):
        code_part, comment_part = _split_code_and_comment(raw_line)
        if comment_part:
            if current is not None:
                current["comments"].append(comment_part)
            else:
                floating_comments.append(comment_part)

        stripped_code = code_part.strip()
        if not stripped_code:
            continue

        for ch in stripped_code:
            if ch == "{":
                if current is not None and current["depth"] == 0 and current["json_lines"]:
                    blocks.append(current)
                    current = None
                if current is None:
                    current = {"json_lines": [], "comments": floating_comments, "depth": 0}
                    floating_comments = []
                current["depth"] += 1
            elif ch == "}":
                if current is not None:
                    current["depth"] -= 1

        if current is not None:
            current["json_lines"].append(code_part)

    if current is not None:
        blocks.append(current)

    parsed_dicts = []
    comments_list = []
    for block in blocks:
        parsed_dicts.append(json.loads("\n".join(block["json_lines"])))
        comments_list.append("\n".join(block["comments"]) if block["comments"] else None)

    return parsed_dicts, comments_list


class ToolCalls(Type):
    class ToolCall(BaseModel):
        name: str
        args: dict[str, Any]

        # Metadata fields: never passed to the underlying `Tool` and excluded from the
        # fingerprint. Purely for logging, debugging, or UI display.
        note: str | None = None
        comment: str | None = None
        annotation: str | None = None
        tags: list[str] | None = None
        priority: str | int | None = None
        meta: dict[str, Any] | None = None

        # Read-only, computed once at creation time from `name` and `args` alone.
        fingerprint: str = ""

