def _parse_calls_and_comments(text: str) -> tuple[list[dict[str, Any]], list[str | None]]:
    """Parse raw text containing JSON tool call objects interleaved with Python comments.

    Each line is split into a code portion and an optional trailing comment. The code
    portions are concatenated and decoded as a sequence of back-to-back JSON objects.
    Comments are then associated with a call as follows:
      - An inline comment (sharing a line with call code) attaches to the call whose span
        that line belongs to (i.e. the call being closed/continued on that line).
      - A standalone comment (on its own line) attaches to the next call that hasn't started
        yet, or - if there is no following call - to the last call, as a trailing comment.

    Returns the parsed dicts alongside the combined (possibly multi-line) comment string for
    each call, or None if no comment was associated with it.
    """
    code_pieces = []
    raw_comments = []  # (line_start_offset, line_end_offset, comment_text, is_inline)
    offset = 0
    for raw_line in text.split("\n"):
        code_part, comment_part = _split_code_and_comment(raw_line)
        start = offset
        end = offset + len(code_part)
        if comment_part:
            raw_comments.append((start, end, comment_part, bool(code_part.strip())))
        code_pieces.append(code_part)
        offset = end + 1  # account for the "\n" used to join lines below

    concatenated = "\n".join(code_pieces)

    decoder = json.JSONDecoder()
    calls = []  # (obj, start_offset, end_offset)
    idx = 0
    n = len(concatenated)
    while idx < n:
        while idx < n and concatenated[idx] in " \t\r\n":
            idx += 1
        if idx >= n:
            break
        obj, end = decoder.raw_decode(concatenated, idx)
        calls.append((obj, idx, end))
        idx = end

    if not calls:
        return [], []

    def most_recent_call_index(pos: int) -> int | None:
        best = None
        for i, (_, start, end) in enumerate(calls):
            if start <= pos <= end:
                return i
            if end <= pos:
                best = i
        return best

    def next_call_index(pos: int) -> int | None:
        for i, (_, start, _) in enumerate(calls):
            if start >= pos:
                return i
        return None

    assigned: list[list[str]] = [[] for _ in calls]
    for start, end, comment_text, is_inline in raw_comments:
        if is_inline:
            call_index = most_recent_call_index(start)
            if call_index is None:
                call_index = next_call_index(start)
        else:
            call_index = next_call_index(start)
            if call_index is None:
                call_index = most_recent_call_index(start)
        if call_index is None:
            call_index = len(calls) - 1
        assigned[call_index].append(comment_text)

    parsed_dicts = [call[0] for call in calls]
    comments_list = ["\n".join(comments) if comments else None for comments in assigned]
    return parsed_dicts, comments_list

